{
var seed = GetInt(parameters, "seed", context.Seed);
    var wallType = GetChoice(parameters, "wallType", "stone");
    var mainColor = GetColor(parameters, "mainColor", Color.FromRgb(180, 170, 155));
    var mortarColor = GetColor(parameters, "mortarColor", Color.FromRgb(140, 130, 115));
    var width = GetFloat(parameters, "width", 0.9f);
    var height = GetFloat(parameters, "height", 0.8f);

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);
    var bg = inputs.Length > 0 ? inputs[0] : null;

    var mR = mainColor.R / 255f;
    var mG = mainColor.G / 255f;
    var mB = mainColor.B / 255f;
    var morR = mortarColor.R / 255f;
    var morG = mortarColor.G / 255f;
    var morB = mortarColor.B / 255f;

    var period = Math.Max(1, size / 3);

    buffer.ParallelForEachPixel((x, y) =>
    {
        var u = (x + 0.5f) / size;
        var v = (y + 0.5f) / size;

        // Wall rectangle
        var left = (1f - width) * 0.5f;
        var right = left + width;
        var top = (1f - height) * 0.5f;
        var bottom = top + height;
        var edgeW = 0.004f;

        var mask = SmoothStep(left - edgeW, left + edgeW, u)
                 * (1f - SmoothStep(right - edgeW, right + edgeW, u))
                 * SmoothStep(top - edgeW, top + edgeW, v)
                 * (1f - SmoothStep(bottom - edgeW, bottom + edgeW, v));

        if (mask < 0.01f)
        {
            if (bg != null) { var (br, bgc, bb, ba) = bg.GetPixel(x, y); buffer.SetPixel(x, y, br, bgc, bb, 0f); }
            else { buffer.SetPixel(x, y, 0f, 0f, 0f, 0f); }
            return;
        }

        // UV within wall region
        var wallU = (u - left) / width;
        var wallV = (v - top) / height;

        float r, g, b;
        switch (wallType)
        {
            case "stone": (r, g, b) = RenderStone(wallU, wallV, mR, mG, mB, morR, morG, morB, size, period, seed); break;
            case "plaster": (r, g, b) = RenderPlaster(wallU, wallV, mR, mG, mB, morR, morG, morB, size, period, seed); break;
            case "planks": (r, g, b) = RenderPlanks(wallU, wallV, mR, mG, mB, morR, morG, morB, size, period, seed); break;
            case "adobe": (r, g, b) = RenderAdobe(wallU, wallV, mR, mG, mB, morR, morG, morB, size, period, seed); break;
            default: r = mR; g = mG; b = mB; break;
        }

        // Edge shadow for 3D panel effect
        var edgeDist = MathF.Min(MathF.Min(u - left, right - u), MathF.Min(v - top, bottom - v));
        if (edgeDist < 0.025f)
        {
            var s = (0.025f - edgeDist) / 0.025f * 0.12f;
            r -= s; g -= s * 0.9f; b -= s * 0.85f;
        }

        r = Math.Clamp(r, 0f, 1f);
        g = Math.Clamp(g, 0f, 1f);
        b = Math.Clamp(b, 0f, 1f);

        if (bg != null)
        {
            var (br, bgc, bb, ba) = bg.GetPixel(x, y);
            r = r * mask + br * (1f - mask);
            g = g * mask + bgc * (1f - mask);
            b = b * mask + bb * (1f - mask);
        }

        buffer.SetPixel(x, y, r, g, b, mask);
    });

    return buffer;

private static (float r, float g, float b) RenderStone(float u, float v, float mR, float mG, float mB, float morR, float morG, float morB, int size, int period, int seed)
{
    // Irregular stone blocks using hash-based cell subdivision
    var gridW = 5f;
    var gridH = 4f;
    var cellW = 1f / gridW;
    var cellH = 1f / gridH;
    var col = (int)(u * gridW);
    var row = (int)(v * gridH);
    var cellU = (u - col * cellW) / cellW;
    var cellV = (v - row * cellH) / cellH;

    // Perturb cell boundaries with hash
    var hx = HashToUnit(col, row, seed + 100);
    var hy = HashToUnit(col + 7, row + 13, seed + 200);
    var ox = (hx - 0.5f) * 0.2f;
    var oy = (hy - 0.5f) * 0.2f;

    // Occasional merged blocks (larger stones)
    var merged = HashToUnit(col, row, seed) > 0.7f && col > 0;
    if (merged)
    {
        cellU = (u - (col - 1) * cellW) / (cellW * 2f);
        cellV = (v - row * cellH) / cellH;
    }

    var localU = cellU - 0.5f - ox;
    var localV = cellV - 0.5f - oy;
    var dist = MathF.Sqrt(localU * localU + localV * localV);

    // Cut stone with slight bevel
    var stoneShape = MathF.Max(MathF.Abs(localU * 1.1f), MathF.Abs(localV * 1.1f));
    var edge = 0.45f;
    var bevel = 0.03f;

    if (stoneShape > edge)
    {
        // Mortar
        var mortarDepth = 1f - MathF.Min(1f, (stoneShape - edge) / bevel);
        var r = Lerp(morR, morR * 0.7f, mortarDepth);
        var g = Lerp(morG, morG * 0.7f, mortarDepth);
        var b = Lerp(morB, morB * 0.7f, mortarDepth);
        return (r, g, b);
    }

    // Stone surface with hash-based variation
    var stoneHash = HashToUnit(col * 7 + row, row * 13 + col, seed + 300);
    var shade = 0.7f + 0.3f * stoneHash;
    var r2 = Math.Clamp(mR * shade + (stoneHash - 0.5f) * 0.08f, 0f, 1f);
    var g2 = Math.Clamp(mG * shade * 0.95f + (stoneHash - 0.5f) * 0.06f, 0f, 1f);
    var b2 = Math.Clamp(mB * shade * 0.9f + (stoneHash - 0.5f) * 0.05f, 0f, 1f);

    // Surface noise
    var noise = TileableFractalNoise(u * 5f, v * 5f, period, 2, 0.5f, 2f, seed + 400);
    var n = (noise - 0.5f) * 0.05f;
    r2 += n; g2 += n * 0.9f; b2 += n * 0.85f;

    // Bevel highlight
    var bevelDist = (edge - stoneShape) / bevel;
    if (bevelDist < 1f)
    {
        var bevelLight = (1f - bevelDist) * 0.12f;
        r2 += bevelLight; g2 += bevelLight * 0.9f; b2 += bevelLight * 0.85f;
    }

    return (Math.Clamp(r2, 0f, 1f), Math.Clamp(g2, 0f, 1f), Math.Clamp(b2, 0f, 1f));
}

private static (float r, float g, float b) RenderPlaster(float u, float v, float mR, float mG, float mB, float morR, float morG, float morB, int size, int period, int seed)
{
    // Smooth plaster with gentle noise
    var noise = TileableFractalNoise(u * 2f, v * 2f, period, 3, 0.55f, 2f, seed + 50);
    var fineNoise = TileableFractalNoise(u * 8f, v * 8f, period, 2, 0.5f, 2f, seed + 150);

    var r = Math.Clamp(mR + (noise - 0.5f) * 0.04f + (fineNoise - 0.5f) * 0.02f, 0f, 1f);
    var g = Math.Clamp(mG + (noise - 0.5f) * 0.035f + (fineNoise - 0.5f) * 0.015f, 0f, 1f);
    var b = Math.Clamp(mB + (noise - 0.5f) * 0.03f + (fineNoise - 0.5f) * 0.01f, 0f, 1f);

    // Subtle horizontal trowel marks
    var trowel = MathF.Sin(v * 40f + noise * 3f) * 0.015f;
    r += trowel; g += trowel * 0.9f; b += trowel * 0.85f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
}

private static (float r, float g, float b) RenderPlanks(float u, float v, float mR, float mG, float mB, float morR, float morG, float morB, int size, int period, int seed)
{
    // Vertical wooden planks with gaps
    var plankCount = 6f;
    var plankW = 1f / plankCount;
    var col = (int)(u * plankCount);
    var cellU = (u - col * plankW) / plankW;
    var gap = 0.04f;

    if (cellU < gap || cellU > 1f - gap)
    {
        // Gap/dark line between planks
        return (morR * 0.4f, morG * 0.35f, morB * 0.3f);
    }

    var plankHash = HashToUnit(col, 0, seed + 60);
    var shade = 0.8f + 0.2f * plankHash;
    var r = mR * shade;
    var g = mG * shade * 0.95f;
    var b = mB * shade * 0.9f;

    // Vertical wood grain
    var grainFreq = 15f + plankHash * 5f;
    var grain = MathF.Sin(u * grainFreq * MathF.PI * 2f + plankHash * 3f) * 0.04f;
    var grainNoise = TileableFractalNoise(u * 3f, v * 4f + col * 2f, period, 2, 0.5f, 2.5f, seed + 80);
    grain += (grainNoise - 0.5f) * 0.04f;

    r += grain; g += grain * 0.7f; b += grain * 0.4f;

    // Knots
    var knotNoise = TileableFractalNoise(u * 10f + col * 2f, v * 6f, period, 1, 0.5f, 2f, seed + 200);
    if (knotNoise > 0.82f)
    {
        var knot = (knotNoise - 0.82f) / 0.18f;
        r -= knot * 0.15f; g -= knot * 0.15f; b -= knot * 0.12f;
    }

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
}

private static (float r, float g, float b) RenderAdobe(float u, float v, float mR, float mG, float mB, float morR, float morG, float morB, int size, int period, int seed)
{
    // Horizontal mud brick pattern
    var rowCount = 5f;
    var colCount = 4f;
    var cellH = 1f / rowCount;
    var cellW = 1f / colCount;
    var row = (int)(v * rowCount);
    var col = (int)(u * colCount);
    var rowOffset = (row % 2 == 0) ? 0f : cellW * 0.5f;

    var cellU = ((u + rowOffset) % cellW) / cellW;
    var cellV = (v * rowCount) % 1f;
    var gap = 0.03f;

    if (cellV < gap || cellV > 1f - gap || cellU < gap || cellU > 1f - gap)
    {
        // Mortar
        var mShade = (cellV < gap || cellV > 1f - gap) ? 0.6f : 0.8f;
        return (morR * mShade, morG * mShade * 0.95f, morB * mShade * 0.9f);
    }

    // Brick surface with variation
    var brickHash = HashToUnit(col, row, seed + 80);
    var shade = 0.7f + 0.3f * brickHash;
    var r = Math.Clamp(mR * shade + (brickHash - 0.5f) * 0.06f, 0f, 1f);
    var g = Math.Clamp(mG * shade * 0.95f + (brickHash - 0.5f) * 0.04f, 0f, 1f);
    var b = Math.Clamp(mB * shade * 0.9f + (brickHash - 0.5f) * 0.03f, 0f, 1f);

    // Horizontal striations
    var streak = MathF.Sin(v * 30f + brickHash * 5f) * 0.02f;
    r += streak; g += streak * 0.9f; b += streak * 0.85f;

    // Surface roughness
    var rough = TileableFractalNoise(u * 6f, v * 6f, period, 2, 0.5f, 2f, seed + 300);
    var roughVal = (rough - 0.5f) * 0.04f;
    r += roughVal; g += roughVal * 0.9f; b += roughVal * 0.85f;

    return (Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f));
    }
}
